import React, { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { mentorsAPI } from '../../services/api';
import './Mentors.css';

const Mentors = () => {
  const [mentors, setMentors] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedField, setSelectedField] = useState('all');
  const [message, setMessage] = useState('');
  const { user } = useAuth();

  const mentorFields = [
    'all',
    'technology',
    'business',
    'design',
    'data-science',
    'marketing',
    'healthcare'
  ];

  useEffect(() => {
    fetchMentors();
  }, [selectedField]);

  const fetchMentors = async () => {
    setLoading(true);
    try {
      const filters = {};
      if (selectedField !== 'all') {
        filters.field = selectedField;
      }
      
      const response = await mentorsAPI.getMentors(filters);
      
      if (response.success) {
        setMentors(response.mentors);
      } else {
        setMessage('Error loading mentors');
      }
    } catch (error) {
      console.error('Error fetching mentors:', error);
      setMessage('Failed to load mentors');
    } finally {
      setLoading(false);
    }
  };

  const requestMentorship = async (mentorId) => {
    try {
      const response = await mentorsAPI.requestMentorship(mentorId);
      
      if (response.success) {
        setMessage('✅ Mentorship request sent successfully!');
        // Refresh mentors to update availability
        fetchMentors();
      } else {
        setMessage('❌ ' + response.message);
      }
    } catch (error) {
      console.error('Error requesting mentorship:', error);
      setMessage('❌ Failed to send request: ' + (error.response?.data?.message || error.message));
    }
  };

  const connectWithMentor = (linkedinUrl) => {
    window.open(linkedinUrl, '_blank');
  };

  // Development only - seed sample data
  const seedMentors = async () => {
    try {
      const response = await mentorsAPI.seedMentors();
      if (response.success) {
        setMessage('✅ Sample mentors added to database!');
        fetchMentors();
      }
    } catch (error) {
      setMessage('❌ Error seeding mentors');
    }
  };

  if (!user) {
    return (
      <div className="mentors-container">
        <div className="container">
          <div className="auth-required">
            <h2>Authentication Required</h2>
            <p>Please log in to connect with mentors.</p>
          </div>
        </div>
      </div>
    );
  }

  if (loading) {
    return (
      <div className="mentors-container">
        <div className="container">
          <div className="loading">Loading mentors...</div>
        </div>
      </div>
    );
  }

  return (
    <div className="mentors-container">
      <div className="container">
        <div className="mentors-header">
          <h1>👥 Career Mentors</h1>
          <p>Connect with experienced professionals who can guide your career journey</p>
          
          {/* Development button - remove in production */}
          <button 
            onClick={seedMentors}
            className="btn btn-secondary"
            style={{ marginTop: '1rem' }}
          >
            Add Sample Mentors (Dev Only)
          </button>
        </div>

        {message && (
          <div className={`message ${message.includes('✅') ? 'success' : 'error'}`}>
            {message}
          </div>
        )}

        <div className="mentors-filters">
          <h3>Filter by Field:</h3>
          <div className="filter-buttons">
            {mentorFields.map(field => (
              <button
                key={field}
                className={`filter-btn ${selectedField === field ? 'active' : ''}`}
                onClick={() => setSelectedField(field)}
              >
                {field.charAt(0).toUpperCase() + field.slice(1).replace('-', ' ')}
              </button>
            ))}
          </div>
        </div>

        <div className="mentors-grid">
          {mentors.map(mentor => (
            <div key={mentor._id} className="mentor-card">
              <div className="mentor-header">
                <img 
                  src={mentor.image || `https://ui-avatars.com/api/?name=${encodeURIComponent(mentor.name)}&background=667eea&color=fff`} 
                  alt={mentor.name} 
                  className="mentor-avatar" 
                />
                <div className="mentor-info">
                  <h3>{mentor.name}</h3>
                  <p className="mentor-title">{mentor.title} at {mentor.company}</p>
                  <div className="mentor-stats">
                    <span className="rating">⭐ {mentor.rating}</span>
                    <span className="sessions">👥 {mentor.totalSessions} sessions</span>
                  </div>
                </div>
              </div>

              <div className="mentor-details">
                <p className="mentor-bio">{mentor.bio}</p>
                
                <div className="mentor-specialization">
                  <strong>Specializes in:</strong>
                  <div className="specialization-tags">
                    {mentor.specialization.map((skill, index) => (
                      <span key={index} className="specialization-tag">{skill}</span>
                    ))}
                  </div>
                </div>

                <div className="mentor-skills">
                  <strong>Skills:</strong>
                  <div className="skills-tags">
                    {mentor.skills?.map((skill, index) => (
                      <span key={index} className="skill-tag">{skill}</span>
                    ))}
                  </div>
                </div>

                <div className="mentor-meta">
                  <span className="experience">🎯 {mentor.experience}</span>
                  <span className={`availability ${mentor.currentMentees < mentor.maxMentees ? 'available' : 'full'}`}>
                    {mentor.currentMentees < mentor.maxMentees ? 
                      `${mentor.maxMentees - mentor.currentMentees} spots available` : 
                      'Currently full'
                    }
                  </span>
                </div>
              </div>

              <div className="mentor-actions">
                {mentor.linkedin && (
                  <button 
                    onClick={() => connectWithMentor(mentor.linkedin)}
                    className="btn btn-secondary"
                  >
                    View LinkedIn
                  </button>
                )}
                <button 
                  onClick={() => requestMentorship(mentor._id)}
                  className="btn btn-primary"
                  disabled={mentor.currentMentees >= mentor.maxMentees}
                >
                  {mentor.currentMentees >= mentor.maxMentees ? 'Currently Full' : 'Request Mentorship'}
                </button>
              </div>
            </div>
          ))}
        </div>

        {mentors.length === 0 && !loading && (
          <div className="no-mentors">
            <h3>No mentors found</h3>
            <p>Try selecting a different field or check back later for new mentors.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default Mentors;
